const text = $input.first().json.body?.text || $input.first().json.text || '';

if (!text) {
  throw new Error('No text provided in request body');
}

const prompt = `You are a legal document parser. Extract the following information from this legal email/document and return it as JSON.

Do NOT invent or hallucinate any information. If a field is unclear or missing, return null for that field.

DOCUMENT TEXT:
${text}

RETURN ONLY VALID JSON — no markdown, no explanation, no code blocks. Just the raw JSON object:

{
  "plaintiffNames": ["PLAINTIFF FULL NAME IN ALL CAPS"],
  "defendantName": "DEFENDANT FULL NAME IN ALL CAPS",
  "caseNumber": "case number string e.g. 2024-CA-004395",
  "circuitNumber": "e.g. 15th",
  "county": "COUNTY NAME IN ALL CAPS e.g. PALM BEACH",
  "corporateRepName": "Full name of the corporate representative already deposed",
  "corporateRepDepositionDate": "Spelled out date e.g. January 20, 2025",
  "targets": [
    {
      "targetName": "Full name in Title Case e.g. Camilo Rueda",
      "targetTitle": "Their title or role e.g. Desk Adjuster or percipient fact witness",
      "targetPronoun": "he or she or they",
      "crTestimony": "What the corporate representative testified about this person",
      "reasonForCompelling": "Why this person has relevant knowledge e.g. she has personal knowledge as to the facts surrounding the roof inspection"
    }
  ]
}

EXTRACTION RULES:
- plaintiffNames: Extract ALL plaintiff names in ALL CAPS. If multiple plaintiffs appear joined by AND, split them into separate array entries.
- defendantName: Usually an insurance company. Return in ALL CAPS.
- caseNumber: The civil case number, usually formatted like 2024-CA-004395.
- circuitNumber: The judicial circuit number e.g. 15th, 19th.
- county: The county name in ALL CAPS e.g. PALM BEACH, MARTIN.
- corporateRepName + corporateRepDepositionDate: The person who was ALREADY deposed (the Corporate Representative) and when their deposition took place.
- targets array: One object per person whose deposition is NOW being requested. Do NOT include the corporate rep in this array.
- targetTitle: Their job title or role at the company. If described as a factual witness, use that description.
- targetPronoun: Use he/she based on the name if obvious. Default to they if uncertain.
- crTestimony: The specific testimony given by the corporate rep about this target witness.
- reasonForCompelling: The reason why compelling this witness is necessary (their relevant knowledge).
- Dates must be spelled out fully: January 20, 2025 — NOT 01/20/2025.
- This is always a plain Motion to Compel — never an Amended Motion.`;

return [{
  json: {
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 2048,
    messages: [
      {
        role: 'user',
        content: prompt
      }
    ]
  }
}];

const response = $input.first().json;
const content = response.content?.[0]?.text || '';

if (!content) {
  throw new Error('Empty response from Claude API');
}

let parsed;
try {
  // Strip markdown code blocks if Claude wrapped the JSON
  const clean = content
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
  parsed = JSON.parse(clean);
} catch (e) {
  throw new Error('Failed to parse AI response as JSON. Raw response: ' + content.substring(0, 300));
}

// Validate required fields
if (!parsed.plaintiffNames || !Array.isArray(parsed.plaintiffNames) || parsed.plaintiffNames.length === 0) {
  throw new Error('No plaintiff names found in document');
}
if (!parsed.targets || !Array.isArray(parsed.targets) || parsed.targets.length === 0) {
  throw new Error('No deposition targets found in document');
}

// Ensure all target pronouns are valid
parsed.targets = parsed.targets.map(t => ({
  ...t,
  targetPronoun: ['he', 'she', 'they'].includes(t.targetPronoun) ? t.targetPronoun : 'they'
}));

return [{ json: parsed }];
